import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

/**
 * Tests for NoWildcardImportsRule with ktlint_official code style.
 * This verifies that the default wildcard imports (java.util.* and kotlinx.android.synthetic.**)
 * are NOT allowed in ktlint_official code style.
 */
class NoWildcardImportsRuleKtlintOfficialTest {
    private val noWildcardImportsRuleAssertThat = assertThatRule { NoWildcardImportsRule() }

    @Nested
    inner class `Given ktlint_official code style` {
        @Test
        fun `Wildcard imports that are allowed by IntelliJ IDEA default should be detected in ktlint_official`() {
            val code =
                """
                import java.util.*
                import kotlinx.android.synthetic.main.layout_name.*
                """.trimIndent()
            noWildcardImportsRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)
                .hasLintViolationsWithoutAutoCorrect(
                    LintViolation(1, 1, "Wildcard import"),
                    LintViolation(2, 1, "Wildcard import"),
                )
        }

        @Test
        fun `All wildcard imports should be detected in ktlint_official`() {
            val code =
                """
                import a.b.*
                import java.util.*
                import kotlinx.android.synthetic.main.layout_name.*
                import react.*
                """.trimIndent()
            noWildcardImportsRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)
                .hasLintViolationsWithoutAutoCorrect(
                    LintViolation(1, 1, "Wildcard import"),
                    LintViolation(2, 1, "Wildcard import"),
                    LintViolation(3, 1, "Wildcard import"),
                    LintViolation(4, 1, "Wildcard import"),
                )
        }
    }

    @Nested
    inner class `Given intellij_idea code style` {
        @Test
        fun `Wildcard imports that are allowed by IntelliJ IDEA default should NOT be detected in intellij_idea`() {
            val code =
                """
                import java.util.*
                import kotlinx.android.synthetic.main.layout_name.*
                """.trimIndent()
            noWildcardImportsRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.intellij_idea)
                .hasNoLintViolations()
        }

        @Test
        fun `Other wildcard imports should be detected in intellij_idea`() {
            val code =
                """
                import a.b.*
                import java.util.*
                import kotlinx.android.synthetic.main.layout_name.*
                import react.*
                """.trimIndent()
            noWildcardImportsRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.intellij_idea)
                .hasLintViolationsWithoutAutoCorrect(
                    LintViolation(1, 1, "Wildcard import"),
                    LintViolation(4, 1, "Wildcard import"),
                )
        }
    }

    @Nested
    inner class `Given android_studio code style` {
        @Test
        fun `Wildcard imports that are allowed by IntelliJ IDEA default should NOT be detected in android_studio`() {
            val code =
                """
                import java.util.*
                import kotlinx.android.synthetic.main.layout_name.*
                """.trimIndent()
            noWildcardImportsRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.android_studio)
                .hasNoLintViolations()
        }

        @Test
        fun `Other wildcard imports should be detected in android_studio`() {
            val code =
                """
                import a.b.*
                import java.util.*
                import kotlinx.android.synthetic.main.layout_name.*
                import react.*
                """.trimIndent()
            noWildcardImportsRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.android_studio)
                .hasLintViolationsWithoutAutoCorrect(
                    LintViolation(1, 1, "Wildcard import"),
                    LintViolation(4, 1, "Wildcard import"),
                )
        }
    }
}
